// === MODULE: shell === v1.0 ===
// Loading animation: a mountain range draws itself left→right, then a little plane takes off and
// climbs over it. Used on the session-restore and app-load screens.
function _tsLoadingScene(){
  return '<div class="ts-scene">'
    +'<svg class="ts-mtns" viewBox="0 0 320 180" preserveAspectRatio="xMidYMid meet" aria-hidden="true">'
      +'<defs><filter id="tsBrush" x="-25%" y="-25%" width="150%" height="150%"><feTurbulence type="fractalNoise" baseFrequency="0.014" numOctaves="2" seed="4" result="n"></feTurbulence><feDisplacementMap in="SourceGraphic" in2="n" scale="6" xChannelSelector="R" yChannelSelector="G"></feDisplacementMap></filter></defs>'
      +'<path class="ts-mtn-path" filter="url(#tsBrush)" pathLength="1" fill="none" stroke="rgba(255,255,255,.95)" stroke-width="6" stroke-linecap="round" stroke-linejoin="round" d="M4 158 L66 104 L118 132 L176 58 L232 128 L288 96 L316 152"></path>'
    +'</svg>'
    +'<div class="ts-runway2"></div>'
    +'<div class="ts-plane2"><svg viewBox="0 0 24 24" width="30" height="30" fill="#ffffff"><path d="M2.5,19h19v2h-19V19z M22.07,9.64c-0.21-0.8-1.04-1.28-1.84-1.06L14.92,10L8,3.57L6.09,4.08l4.15,7.19l-4.97,1.33l-1.97-1.54l-1.45,0.39l2.59,4.49l17.28-4.64C21.81,11.27,22.28,10.44,22.07,9.64z"></path></svg></div>'
    +'</div>'
    +'<div class="ts-loading-text">Loading...</div>'
    +'<button onclick="window.tsSkipLoad()" style="margin-top:16px;padding:8px 22px;border-radius:20px;border:1px solid rgba(255,255,255,.4);background:rgba(255,255,255,.08);color:#fff;font-size:13px;font-weight:700;letter-spacing:.03em;cursor:pointer">Skip →</button>';
}
// Skip the loading screen and go straight to the app.
window.tsSkipLoad=function(){S._appLoading=false;S._authRestoring=false;if(typeof render==='function')render();};
function renderIOSBanner(){
  const isIOS=/iPhone|iPad|iPod/.test(navigator.userAgent);
  const isStandalone=window.navigator.standalone===true;
  const dismissed=localStorage.getItem('hs_banner_dismissed');
  if(!isIOS||isStandalone||dismissed) return '';
  return`<div style="position:fixed;bottom:0;left:0;right:0;background:linear-gradient(135deg,#7B9EC6,#4A6D96);padding:12px 16px;z-index:9997;display:flex;align-items:center;gap:10px;padding-bottom:max(12px,env(safe-area-inset-bottom))">
    <div style="font-size:11px;color:#fff;flex:1;line-height:1.4">
      <strong>Add to Home Screen</strong> for the best experience — tap 
      <span style="display:inline-block;border:1px solid rgba(255,255,255,.5);border-radius:4px;padding:0 4px;font-size:10px">⎙ Share</span>
      then <strong>Add to Home Screen</strong>
    </div>
    <button onclick="localStorage.setItem('hs_banner_dismissed','1');this.closest(\'div[style*=fixed]\').remove()" style="background:rgba(255,255,255,.2);border:none;border-radius:6px;color:#fff;padding:6px 10px;font-size:11px;cursor:pointer;white-space:nowrap">Dismiss</button>
  </div>`;
}

// safeRender: defers render if an input/select/textarea is currently focused
let _rtRenderPending=false;
let _rtRenderMaxWait=null;
const _PICKER_TYPES=/^(date|datetime-local|month|week|time|color|range|file|checkbox|radio)$/;
function _isPickerOpen(){var a=document.activeElement;return !!(a&&a.tagName==='INPUT'&&_PICKER_TYPES.test(a.type||''));}
function safeRender(){
  const ae=document.activeElement;
  const tag=ae&&ae.tagName;
  if(tag==='INPUT'||tag==='SELECT'||tag==='TEXTAREA'){
    _rtRenderPending=true;
    // Safety net: force render after 3s even if input stays focused — but NEVER while a
    // native date/time picker is open (it would close the picker mid-use), so keep waiting.
    if(!_rtRenderMaxWait)_rtRenderMaxWait=setTimeout(function _mw(){
      if(_isPickerOpen()){_rtRenderMaxWait=setTimeout(_mw,2000);return;}
      _rtRenderPending=false;_rtRenderMaxWait=null;render();
    },3000);
  } else {render();}
}
// Auto-select input content on focus (type-to-overwrite) — skip date/time/etc. pickers.
document.addEventListener('focusin',function(e){var t=e.target;if(t&&t.tagName==='INPUT'&&typeof t.select==='function'&&!_PICKER_TYPES.test(t.type||'')){try{t.select();}catch(_){}}});

// Cmd+Z / Ctrl+Z global undo for loadsheet
document.addEventListener('keydown',function(e){
  if((e.metaKey||e.ctrlKey)&&e.key==='z'&&!e.shiftKey){
    if((S.tab==='loadsheet'||(S.tab||'').startsWith('ls_'))&&S._lsFormUndoStack&&S._lsFormUndoStack.length){
      e.preventDefault();
      window.lsUndo();
    }
  }
  // ⌘/Ctrl + ← / → cycle the DATE one day at a time on the Rezdy-data pages (Bookings / Seatmap /
  // Loadsheets), mirroring the ◁ ▷ buttons. Skip while typing in a field or a modal is open.
  if((e.key==='ArrowLeft'||e.key==='ArrowRight')&&(e.metaKey||e.ctrlKey)&&!e.altKey&&!e.shiftKey){
    var _da=document.activeElement,_dt=_da&&_da.tagName;
    if(_dt==='INPUT'||_dt==='SELECT'||_dt==='TEXTAREA'||(_da&&_da.isContentEditable))return;
    if(S._rzCheckinDraft||S._rzNewBkDraft||S.showAccount||S._drawerOpen)return;
    if(((S.section==='operations'&&(S.tab==='bookings'||S.tab==='rseatmap'||S.tab==='rloadsheets'||S.tab==='ground'))||S.section==='calendar')&&typeof window.rezdyShiftDate==='function'){
      e.preventDefault();window.rezdyShiftDate(e.key==='ArrowRight'?1:-1);
    }
    return;
  }
  // ← / → cycle the Operations sub-tabs (Bookings ↔ Seatmap ↔ Loadsheets ↔ Saved ↔ Charter),
  // unless focus is in a field or a modal/account panel is open.
  if((e.key==='ArrowLeft'||e.key==='ArrowRight')&&!e.metaKey&&!e.ctrlKey&&!e.altKey){
    var _ae=document.activeElement,_t=_ae&&_ae.tagName;
    if(_t==='INPUT'||_t==='SELECT'||_t==='TEXTAREA'||(_ae&&_ae.isContentEditable))return;
    if(S._rzCheckinDraft||S._rzNewBkDraft||S.showAccount||S._drawerOpen)return;
    var _dir=(e.key==='ArrowRight')?1:-1;
    // Roster (calendar view): shift the displayed week.
    if(S.section==='roster'&&(S.rosterTab||'view')==='view'&&typeof window.rosterShiftWeek==='function'){
      e.preventDefault();window.rosterShiftWeek(_dir);return;
    }
    // Maintenance: cycle the tier-2 sub-tabs.
    if(S.section==='maintenance'&&typeof _maintTabIds==='function'){
      var _mt=_maintTabIds(),_mc=_mt.indexOf(S.maintTab||'overview');if(_mc<0)_mc=0;
      var _mn=_mc+_dir;if(_mn<0)_mn=_mt.length-1;if(_mn>=_mt.length)_mn=0;
      e.preventDefault();S.maintTab=_mt[_mn];render();return;
    }
    // Calendar: cycle the day.
    if(S.section==='calendar'&&typeof window.rezdyShiftDate==='function'){
      e.preventDefault();window.rezdyShiftDate(_dir);return;
    }
    if(S.section!=='operations')return;
    var _tabs=['bookings','rseatmap','rloadsheets','saved'];if(typeof hasRolePerm==='function'&&hasRolePerm('charter'))_tabs.push('charter');_tabs.push('ground');
    var _cur=_tabs.indexOf(S.tab);if(_cur<0)_cur=0;
    var _next=_cur+_dir;if(_next<0)_next=_tabs.length-1;if(_next>=_tabs.length)_next=0;
    e.preventDefault();if(typeof window.switchOpsTab==='function')window.switchOpsTab(_tabs[_next]);
  }
});
// Cycle the tier-2 sub-tabs of the current section (shared by arrow keys and mobile swipe).
window._cycleTier2=function(dir){
  if(S._rzCheckinDraft||S._rzNewBkDraft||S.showAccount||S._drawerOpen)return;
  if(S.section==='operations'){
    var tabs=['bookings','rseatmap','rloadsheets','saved'];if(typeof hasRolePerm==='function'&&hasRolePerm('charter'))tabs.push('charter');tabs.push('ground');
    var cur=tabs.indexOf(S.tab);if(cur<0)cur=0;var nx=(cur+dir+tabs.length)%tabs.length;
    if(typeof window.switchOpsTab==='function')window.switchOpsTab(tabs[nx]);
  } else if(S.section==='calendar'){
    // Calendar: cycle the DAY (swipe outside the grid / arrow keys).
    if(typeof window.rezdyShiftDate==='function'){window.rezdyShiftDate(dir);}
  }
};
// Mobile: a clear horizontal swipe cycles the tier-2 tabs. Guards so it never hijacks a
// horizontally-scrollable element (e.g. the seatmap fleet row) or ordinary vertical scrolling.
(function(){
  var x0=null,y0=null,t0=0,scrollGuard=false;
  document.addEventListener('touchstart',function(e){
    if(!e.touches||e.touches.length!==1){x0=null;return;}
    var t=e.touches[0];x0=t.clientX;y0=t.clientY;t0=Date.now();scrollGuard=false;
    var el=e.target;
    while(el&&el!==document.body&&el.nodeType===1){
      if(el.scrollWidth-el.clientWidth>8){var cs=getComputedStyle(el);if(/(auto|scroll)/.test(cs.overflowX)){scrollGuard=true;break;}}
      el=el.parentElement;
    }
  },{passive:true});
  document.addEventListener('touchend',function(e){
    if(x0==null)return;var ch=e.changedTouches&&e.changedTouches[0];if(!ch){x0=null;return;}
    var dx=ch.clientX-x0,dy=ch.clientY-y0,dt=Date.now()-t0;var guard=scrollGuard;x0=null;
    if(guard)return;
    if(dt>600)return;                                   // too slow to be a swipe
    if(Math.abs(dx)<60||Math.abs(dx)<Math.abs(dy)*1.8)return; // must be a decisive horizontal swipe
    window._cycleTier2(dx<0?1:-1);                      // swipe left → next, right → previous
  },{passive:true});
})();
// Fire deferred render when focus fully leaves all inputs
document.addEventListener('focusout',function(e){
  if(!_rtRenderPending)return;
  const next=e.relatedTarget;
  const nt=next&&next.tagName;
  if(nt!=='INPUT'&&nt!=='SELECT'&&nt!=='TEXTAREA'){
    _rtRenderPending=false;
    clearTimeout(_rtRenderMaxWait);_rtRenderMaxWait=null;
    render();
  }
});

// Which permission a top-level section requires. Everything routes through hasRolePerm so the
// permission grid governs access for every role (superadmin is all-true via DEFAULT_ROLE_PERMS).
// 'leave' (My Leave) is the universal fallback every role can reach.
function _sectionAllowed(sec){
  if(!S.user)return false;
  switch(sec){
    case 'maintenance': return hasRolePerm('maintenance');
    case 'roster':      return hasRolePerm('roster');
    case 'leave':       return hasRolePerm('leave');
    case 'rezdy':       return hasRolePerm('rezdy');
    case 'calendar':    return hasRolePerm('calendar');
    case 'settings':    return hasRolePerm('admin_users')||hasRolePerm('admin_crew');
    case 'operations':  return hasRolePerm('operations');
    case 'flightduty':  return (hasRolePerm('flightduty'))||!!(S.user&&S.user.superAdmin);
    case 'businessplan':return (hasRolePerm('businessplan'))||!!(S.user&&S.user.superAdmin);
    case 'flightrecord':return (hasRolePerm('flightrecord'))||!!(S.user&&S.user.superAdmin);
    case 'resources':   return hasRolePerm('resources'); // gated further by the feature toggle in nav
    case 'training':    return !!S.user; // training is available to every signed-in user
    case 'sms':         return hasRolePerm('sms')||!!(S.user&&S.user.superAdmin);           // placeholders — visible to superadmin for now; perms later
    case 'ground':      return hasRolePerm('ground')||!!(S.user&&S.user.superAdmin);
    case 'vehicleprestart': return hasRolePerm('vehicle_prestart')||!!(S.user&&S.user.superAdmin);
    case 'trainingmod': return hasRolePerm('training_mod')||!!(S.user&&S.user.superAdmin);
    case 'logbook':     return !!S.user; // every signed-in pilot has a personal logbook
    case 'pilotbag':    return _pilotBagTabDefs().length>0; // bundles Flight Record / Logbooks / Flight & Duty
    default:            return true;
  }
}
// ── Pilot Bag: Flight Record / Logbooks / Flight & Duty bundled into one tier-1 section ──
function _pilotBagTabDefs(){
  if(!S.user)return [];
  var sa=!!(S.user&&S.user.superAdmin);
  var t=[];
  if(hasRolePerm('flightrecord')||sa)t.push({id:'flightrecord',lbl:'Flight Record',icon:'🛩️'});
  t.push({id:'logbook',lbl:'Logbooks',icon:'📒'});                 // every signed-in user gets a personal logbook
  if(hasRolePerm('flightduty')||sa)t.push({id:'flightduty',lbl:'Flight & Duty',icon:'🕓'});
  return t;
}
function _pilotBagTab(){
  var defs=_pilotBagTabDefs();if(!defs.length)return null;
  var cur=S._pilotBagTab;
  if(cur&&defs.some(function(d){return d.id===cur;}))return cur;
  return defs[0].id;
}
window.setPilotBagTab=function(id){S._pilotBagTab=id;S.section='pilotbag';S._drawerOpen=false;render();};
function _firstAllowedSection(){
  var order=['operations','calendar','maintenance','roster','leave','settings'];
  for(var i=0;i<order.length;i++){if(_sectionAllowed(order[i]))return order[i];}
  return 'leave';
}
// Simple "coming soon" page for placeholder sections (reminders of what to build next).
function _placeholderPage(title,sub){
  return '<div class="page"><div class="card" style="text-align:center;padding:48px 24px"><div style="font-size:40px;margin-bottom:10px">🚧</div><div class="st" style="margin-bottom:4px">'+title+'</div><p style="font-size:13px;color:var(--text3);margin:0">'+sub+' — coming soon. Placeholder for a future build.</p></div></div>';
}
function _defaultTabFor(sec){
  return sec==='maintenance'?'maintenance':sec==='operations'?'bookings':sec==='settings'?'admin':sec;
}
// ── "Open the app to" preference (per device, in localStorage 'ts_home') ────────
var HOME_OPTIONS=[
  {id:'bookings',label:'Bookings',section:'operations',tab:'bookings'},
  {id:'rseatmap',label:'Seatmap',section:'operations',tab:'rseatmap'},
  {id:'rloadsheets',label:'Loadsheets',section:'operations',tab:'rloadsheets'},
  {id:'ground',label:'Transport (Ground)',section:'operations',tab:'ground'},
  {id:'calendar',label:'Calendar',section:'calendar'},
  {id:'maintenance',label:'Maintenance',section:'maintenance'},
  {id:'roster',label:'Roster',section:'roster'},
  {id:'leave',label:'Leave',section:'leave'},
  {id:'flightrecord',label:'Flight Record',section:'pilotbag',tab:'flightrecord'},
  {id:'logbook',label:'Logbook',section:'pilotbag',tab:'logbook'},
  {id:'flightduty',label:'Flight & Duty',section:'pilotbag',tab:'flightduty'},
  {id:'resources',label:'Resource board',section:'resources'},
  {id:'businessplan',label:'Business Plan',section:'businessplan'},
  {id:'settings',label:'Settings',section:'settings',tab:'admin'},
  {id:'training',label:'Training',section:'training'}
];
function _homeOptAll(){return HOME_OPTIONS.filter(function(o){return (typeof _sectionAllowed!=='function')||_sectionAllowed(o.section);});}
function _homeGet(){try{return (typeof lsGet==='function'&&lsGet('ts_home'))||'';}catch(e){return '';}}
function _homeOpt(id){for(var i=0;i<HOME_OPTIONS.length;i++)if(HOME_OPTIONS[i].id===id)return HOME_OPTIONS[i];return null;}
function _applyHomePref(){var o=_homeOpt(_homeGet());if(!o)return;if((typeof _sectionAllowed==='function')&&!_sectionAllowed(o.section))return;S.section=o.section;S.tab=o.tab||_defaultTabFor(o.section);if(o.section==='pilotbag'&&o.tab)S._pilotBagTab=o.tab;}
window.homeSetSearch=function(v){S._homeSearch=v;render();};
window.homeSet=function(id){try{if(id)lsSet('ts_home',id);else localStorage.removeItem('ts_home');}catch(e){}if(typeof toast==='function')toast(id?('Opens to '+((_homeOpt(id)||{}).label||id)):'Opens to your default page','ok');render();};
function _renderHomePicker(){
  var cur=_homeGet();var q=String(S._homeSearch||'').toLowerCase();
  var opts=_homeOptAll().filter(function(o){return !q||o.label.toLowerCase().indexOf(q)>=0;});
  var h='<div style="font-size:12px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;margin:2px 0 8px">Open the app to</div>';
  h+='<input id="home_search" type="text" oninput="window.homeSetSearch(this.value)" placeholder="Search pages…" value="'+String(S._homeSearch||'').replace(/"/g,'&quot;')+'" style="width:100%;box-sizing:border-box;padding:8px 11px;background:var(--card2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;outline:none;margin-bottom:6px">';
  h+='<div style="max-height:170px;overflow-y:auto;display:flex;flex-direction:column;gap:4px;margin-bottom:16px">';
  var defOn=!cur;
  h+='<button onclick="window.homeSet(\'\')" style="text-align:left;padding:8px 11px;border-radius:8px;border:1px solid '+(defOn?'var(--accent)':'var(--border2)')+';background:'+(defOn?'rgba(124,58,237,.12)':'transparent')+';color:var(--text2);font-size:13px;font-weight:600;cursor:pointer">'+(defOn?'✓ ':'')+'Default (first available page)</button>';
  opts.forEach(function(o){var on=o.id===cur;h+='<button onclick="window.homeSet(\''+o.id+'\')" style="text-align:left;padding:8px 11px;border-radius:8px;border:1px solid '+(on?'var(--accent)':'var(--border2)')+';background:'+(on?'rgba(124,58,237,.12)':'transparent')+';color:var(--text2);font-size:13px;font-weight:'+(on?'800':'600')+';cursor:pointer">'+(on?'✓ ':'')+o.label+'</button>';});
  if(!opts.length)h+='<div style="font-size:12px;color:var(--text3);padding:6px">No pages match.</div>';
  h+='</div>';
  return h;
}
function render(){
  const r=document.getElementById('root');
  if(!r)return;
  document.body.classList.toggle('wide-mode',!!S.wideMode);
  // Auto-detect mobile on first render, and keep it reactive (iPad rotate / split-view / window
  // resize). Same detection formula as before — only now it re-evaluates instead of freezing at boot.
  if(typeof S._mobileInit==='undefined'){
    S._mobileInit=true;
    if(typeof S.mobileView==='undefined')S.mobileView=/iPhone|iPad|iPod|Android/i.test(navigator.userAgent)&&window.innerWidth<800;
    try{
      var _recalcMobile=function(){var nv=/iPhone|iPad|iPod|Android/i.test(navigator.userAgent)&&window.innerWidth<800;if(nv!==S.mobileView){S.mobileView=nv;render();}};
      var _mqT;var _onViewportChange=function(){clearTimeout(_mqT);_mqT=setTimeout(_recalcMobile,150);};
      window.addEventListener('resize',_onViewportChange);
      window.addEventListener('orientationchange',_onViewportChange);
    }catch(e){}
  }
  document.body.classList.toggle('mobile-view',!!S.mobileView);
  // ── Nav migration (v24.14): the old 'rezdy' section was split — Calendar is now its own
  // tier-1 section, Pickups/My Pickups moved to Operations ▸ Ground. Remap any restored last-view
  // or stale deep-link so old state still lands somewhere sensible.
  if(S.section==='rezdy'){
    if(S.rezdyTab==='pickups'){S.section='operations';S.tab='ground';S._groundTab='pickups';}
    else if(S.rezdyTab==='mypickups'){S.section='operations';S.tab='ground';S._groundTab='mypickups';}
    else{S.section='calendar';}
  }
  // ── Nav migration (v26.12): Flight Record / Logbooks / Flight & Duty are now bundled into one
  // 'pilotbag' section as tier-2 tabs. Remap any restored last-view / home-pref / deep link.
  if(S.section==='flightrecord'||S.section==='logbook'||S.section==='flightduty'){S._pilotBagTab=S.section;S.section='pilotbag';}
  // ── Remember the current view so a reload returns to the same page ──
  // Gated on S._viewRestored so the default-view renders during boot DON'T overwrite the
  // saved last view before _restoreLastView() has had a chance to read and apply it.
  if(S.user&&S._viewRestored){try{var _lv=JSON.stringify({section:S.section||'operations',tab:S.tab||'bookings',activeTabId:S.activeTabId||null,activeManifestTabId:S.activeManifestTabId||null,savedTab:S.savedTab||null,groundTab:S._groundTab||null,pilotBagTab:S._pilotBagTab||null});if(_lv!==S.__lastViewStr){S.__lastViewStr=_lv;localStorage.setItem('ts_lastview',_lv);}}catch(e){}}
  // ── Preserve focused input across re-renders ──
  const _ae=document.activeElement;
  const _aeId=_ae?.id||null;
  const _aeRow=_ae?.dataset?.row;
  const _aeField=_ae?.dataset?.field;
  const _aeSS=_ae?.selectionStart??null;
  const _aeSE=_ae?.selectionEnd??null;
  if(!S.user){
    // Show login overlay, hide app
    let lo=document.getElementById('login-overlay');
    if(!lo){
      lo=document.createElement('div');
      lo.id='login-overlay';
      document.body.appendChild(lo);
    }
    lo.style.display='flex';
    if(S._authRestoring){
      // We have a saved session and are restoring it on refresh — show the loading spinner, NOT
      // the login form, so the login screen doesn't flash before auth resolves.
      lo.style.backgroundImage="linear-gradient(to bottom,rgba(0,0,0,.42),rgba(0,0,0,.68)),url('"+BG_IMG+"')";
      // Set the intro scene ONCE so re-renders during boot don't restart the animation mid-play.
      if(!lo.querySelector('.ts-scene'))lo.innerHTML='<div id="loading-overlay" style="display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center">'+_tsLoadingScene()+'</div>';
    } else {
      lo.style.backgroundImage=`linear-gradient(to bottom,rgba(0,0,0,.32),rgba(0,0,0,.58)),url('${BG_IMG}')`;
      // Build the login form ONCE (or when the reset step changes) so a stray re-render — presence
      // ticks, realtime, etc. — can't rebuild it and steal focus mid-typing / break Tab order. The
      // only live bit (the error banner) is updated in place.
      var _lgStep=String(S.resetStep||0);
      if(!lo.querySelector('#login-form')||lo.dataset.lgStep!==_lgStep){lo.innerHTML=renderLoginInner();lo.dataset.lgStep=_lgStep;}
      else{var _ee=lo.querySelector('#login-err');if(_ee){_ee.innerHTML=S.loginErr||'';_ee.style.display=S.loginErr?'block':'none';}}
    }
    r.style.display='none';
    return;
  }
  // Show loading screen (reuse login overlay so bg stays in place)
  let lo=document.getElementById('login-overlay');
  if(S._appLoading){
    if(!lo){lo=document.createElement('div');lo.id='login-overlay';document.body.appendChild(lo);}
    lo.style.display='flex';
    lo.style.backgroundImage="linear-gradient(to bottom,rgba(0,0,0,.42),rgba(0,0,0,.68)),url('"+BG_IMG+"')";
    // Set the intro scene ONCE so re-renders during boot don't restart the animation mid-play.
    if(!lo.querySelector('.ts-scene'))lo.innerHTML='<div id="loading-overlay" style="display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center">'+_tsLoadingScene()+'</div>';
    r.style.display='none';
    return;
  }
  // Hide login, show app
  if(lo) lo.style.display='none';
  r.style.display='';
  // Access is permission-driven (the permission grid is the single source of truth for every
  // role — no hardcoded role gates). If the user is on a section they're not permitted to
  // (default boot, a stale last-view, or a revoked permission), bounce them to their first
  // allowed section. Superadmin passes everything via DEFAULT_ROLE_PERMS; admin follows the grid.
  // Per-user "open the app to" preference — applied once on the first authed render.
  if(S.user&&!S._homeApplied){S._homeApplied=true;if(typeof _applyHomePref==='function')_applyHomePref();}
  if(S.user&&!_sectionAllowed(S.section||'operations')){var _fs=_firstAllowedSection();S.section=_fs;S.tab=_defaultTabFor(_fs);}
  r.innerHTML=renderApp()+renderAccountModal()+renderToasts()+renderIOSBanner();
  if(S.tab&&S.tab.startsWith('ls_'))setTimeout(_applyLsFlash,50);
  if(S._pendingFlash&&S._pendingFlash.length){var _pf=S._pendingFlash;S._pendingFlash=[];setTimeout(function(){_triggerFlash(_pf);},50);}
  if((S.tab==='loadsheet'&&S.activeTabId)||S.tab.startsWith('ls_')||(S._rzLsActiveId&&S.activeTabId&&S.tab==='rloadsheets')){setupSig();var lf=S.form;if(lf&&lf.dep&&lf.dest&&S._lsMapOpen)renderRouteMap('ls-map',[{from:lf.dep,to:lf.dest}]);}
  // ── Restore focus after re-render ──
  // Force-focus (set by Tab handler) takes priority over activeElement detection
  if(_ffRow!==null){
    const _re=document.querySelector('[data-row="'+_ffRow+'"][data-field="'+_ffField+'"]');
    if(_re){_re.focus();try{_re.select();}catch{}}
    _ffRow=null;_ffField=null;
  } else if(_aeRow!==undefined&&_aeField){
    const _re=document.querySelector('[data-row="'+_aeRow+'"][data-field="'+_aeField+'"]');
    if(_re){_re.focus();try{_re.setSelectionRange(_aeSS,_aeSE);}catch{}}
  } else if(_aeId&&S.tab!=='manifest'){
    const _re=document.getElementById(_aeId);
    if(_re){_re.focus();try{_re.setSelectionRange(_aeSS,_aeSE);}catch{}}
  }
}

// ── Login ──
// ── Toast/pill notification (replaces alert) ──
function toast(msg, type){
  type=type||'info';
  S.toasts=S.toasts||[];
  const id='t'+Date.now();
  S.toasts.unshift({id,msg,type,ts:Date.now()});
  S.toasts=S.toasts.slice(0,5); // max 5 toasts
  // Auto-dismiss after 5 seconds
  setTimeout(function(){
    S.toasts=(S.toasts||[]).filter(function(t){return t.id!==id;});
    const el=document.getElementById('toast-'+id);
    if(el) el.style.opacity='0';
    setTimeout(function(){safeRender();},300);
  },5000);
  render();
}
function renderToasts(){
  const toasts=S.toasts||[];
  if(!toasts.length) return '';
  return '<div class="toast-wrap" style="position:fixed;z-index:9998;display:flex;flex-direction:column;gap:8px;max-width:340px">'+
    toasts.map(function(t){
      const bg=t.type==='ok'?'#166534':t.type==='err'?'#7f1d1d':t.type==='warn'?'#78350f':'#1e3a5f';
      const border=t.type==='ok'?'#22c55e':t.type==='err'?'#ef4444':t.type==='warn'?'#f59e0b':'#3b82f6';
      const txt=t.type==='ok'?'#86efac':t.type==='err'?'#fca5a5':t.type==='warn'?'#fde68a':'#93c5fd';
      return'<div id="toast-'+t.id+'" style="background:'+bg+';border:1px solid '+border+';border-radius:10px;padding:10px 14px;font-size:13px;color:'+txt+';display:flex;align-items:flex-start;gap:10px;box-shadow:0 4px 16px rgba(0,0,0,.4);transition:opacity .3s">'+
        '<span style="flex:1;line-height:1.4">'+esc(t.msg)+'</span>'+
        '<button onclick="S.toasts=(S.toasts||[]).filter(function(x){return x.id!==\''+t.id+'\';});render()" style="background:none;border:none;color:'+txt+';cursor:pointer;font-size:16px;padding:0;line-height:1;opacity:.7;flex-shrink:0">&times;</button>'+
        '</div>';
    }).join('')+
  '</div>';
}

// ── Centralised audit logging ──
async function auditLog(action, detail){
  const u=S.user;
  const entry={
    time: new Date().toISOString(),
    user: u?.email||'unknown',
    name: u?.name||u?.email||'unknown',
    role: u?.role||'unknown',
    action,
    detail: typeof detail==='object'?JSON.stringify(detail):String(detail||''),
    device: navigator.userAgent.slice(0,120),
  };
  // Store locally
  S.auditLog=S.auditLog||[];
  S.auditLog.unshift(entry);
  lsSet('ts_audit_log',S.auditLog.slice(0,1000));
  // Push to Supabase ts_audit_log table (use the signed-in JWT via SH so rows are
  // attributed to the authenticated user and a mid-session token refresh is honoured;
  // SH falls back to the anon key pre-login, which is correct for login-failure rows).
  try{
    await _sbFetch(SB+'/rest/v1/ts_audit_log',{
      method:'POST',
      headers:{...SH,'Prefer':'return=minimal'},
      body:JSON.stringify({user_email:entry.user,user_name:entry.name,role:entry.role,action:entry.action,detail:entry.detail,device:entry.device,created_at:entry.time})
    });
  }catch(e){console.warn('Audit log push failed:',e);}
}

// Convenience: log a failed login attempt (no S.user yet)
async function auditLoginFail(email, reason){
  const entry={
    time:new Date().toISOString(),
    user:email||'unknown',
    name:'—',
    role:'—',
    action:'login_fail',
    detail:reason||'Invalid credentials',
    device:navigator.userAgent.slice(0,120),
  };
  S.auditLog=S.auditLog||[];
  S.auditLog.unshift(entry);
  lsSet('ts_audit_log',S.auditLog.slice(0,1000));
  try{
    await fetch(SB+'/rest/v1/ts_audit_log',{
      method:'POST',
      headers:{'Content-Type':'application/json','apikey':SK,'Authorization':'Bearer '+SK,'Prefer':'return=minimal'},
      body:JSON.stringify({user_email:entry.user,user_name:'—',role:'—',action:'login_fail',detail:entry.detail,device:entry.device,created_at:entry.time})
    });
  }catch(e){}
}

