// ── MANIFEST ──
function _triggerFlash(ids){
  if(!ids)return;if(!Array.isArray(ids))ids=[ids];
  ids.forEach(function(id){
    var el=document.getElementById(id);
    if(el&&!el.classList.contains('ls-flash')){
      el.classList.add('ls-flash');
      setTimeout(function(){if(el)el.classList.remove('ls-flash');},2000);
    }
  });
}
function _applyLsFlash(){
  if(!S._lsFlash)return;
  var now=Date.now();
  // All loadsheet live-edit signals (fuel/route/seats) flash the combined loadsheet card.
  var el=document.getElementById('lsf-loading');
  Object.keys(S._lsFlash).forEach(function(k){
    var age=now-S._lsFlash[k];
    if(age>2200){delete S._lsFlash[k];return;}   // only drop the key once expired
    if(el&&!el.classList.contains('ls-flash')){
      el.classList.add('ls-flash');
      var rem=Math.max(100,2000-age);
      setTimeout(function(){if(el)el.classList.remove('ls-flash');},rem);
    }
  });
  _triggerFlash('flash-loadsheet');
}
// Simple "coming soon" page for a placeholder tier-1 section.
function _renderPlaceholderSection(title,icon,sub){
  return '<div class="card" style="text-align:center;padding:56px 24px;max-width:560px;margin:24px auto">'+
    '<div style="font-size:46px;margin-bottom:12px">'+icon+'</div>'+
    '<div class="st" style="justify-content:center;font-size:20px;margin-bottom:6px">'+title+'</div>'+
    '<div style="font-size:13px;color:var(--text3);line-height:1.5;margin-bottom:14px">'+sub+'</div>'+
    '<span style="display:inline-block;font-size:11px;font-weight:800;letter-spacing:.05em;color:#c084fc;background:rgba(124,58,237,.14);border:1px solid rgba(124,58,237,.4);padding:4px 12px;border-radius:14px">COMING SOON</span>'+
  '</div>';
}
function renderOperations(){
  const opsTab=S.tab||'bookings';
  // Content routing — the Rezdy-powered Operations flow: Bookings / Seatmap / Loadsheets.
  // (The legacy manifest/seatmap/loadsheet-tab UI was retired in v23.76.)
  if(opsTab==='rseatmap'){try{return window.rezdyOpsSeatmap();}catch(e){return '<div class="card" style="color:var(--err-text)">Seatmap error: '+e.message+'</div>';}}
  if(opsTab==='rloadsheets'){try{return window.rezdyOpsLoadsheets();}catch(e){return '<div class="card" style="color:var(--err-text)">Loadsheets error: '+e.message+'</div>';}}
  if(opsTab==='saved'){if(S._presSection&&S._presSection!=='saved')broadcastPresence(null);return renderSaved();}
  if(opsTab==='charter'){if(S._presSection)broadcastPresence(null);return '<div id="flash-charter">'+renderCharter()+'</div>';}
  if(opsTab==='ground'){if(S._presSection)broadcastPresence(null);return renderGround();}
  // Default / fallback (including 'bookings' and any stale legacy tab id) → Bookings.
  try{return window.rezdyOpsBookings();}catch(e){return '<div class="card" style="color:var(--err-text)">Bookings error: '+e.message+'</div>';}
}

